import itemsData from "./app/components/items.json";

export default function ItemButtons() {
  return (
    <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-6 gap-4 p-4">
      {itemsData.map((item) => {
        const imagePath = `/items/${item["Item Name"]}.png`;
        
        return (
          <button
            key={item["Item Name"]}
            className="group relative overflow-hidden rounded-lg border-2 border-transparent hover:border-blue-500 transition-all"
            onClick={() => console.log('Selected:', item["Item Name"])}
          >
            {/* Image with fallback */}
            <img 
              src={imagePath}
              alt={item["Item Name"]}
              className="w-full h-32 object-contain p-2"
              onError={(e) => {
                // Handle missing images
                e.currentTarget.style.display = 'none';
              }}
            />
            
            {/* Hover overlay */}
            <div className="absolute inset-0 bg-black/80 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
              <span className="text-white text-center text-sm p-2">
                {item["Item Name"].replace(/_/g, ' ')}
              </span>
            </div>
          </button>
        );
      })}
    </div>
  );
}